 * Unit tests for lib/chunk-text.ts — sentence-aware text chunker.
 */

import { describe, it, expect } from 'vitest';
import { chunkText } from './chunk-text';

// ─── Empty / whitespace-only ──────────────────────────────────────────────

describe('chunkText', () => {
  describe('empty and whitespace-only inputs', () => {
    it('returns [] for empty string', () => {
      expect(chunkText('', 10)).toEqual([]);
    });

    it('returns [] for whitespace-only string', () => {
      expect(chunkText('   ', 10)).toEqual([]);
    });

    it('returns [] for tab and newline whitespace', () => {
      expect(chunkText('\t\n  \t', 5)).toEqual([]);
    });
  });

  // ─── Throws on invalid maxLength ────────────────────────────────────────

  describe('throws on invalid maxLength', () => {
    it('throws when maxLength is 0', () => {
      expect(() => chunkText('text', 0)).toThrow('maxLength must be a positive number');
    });

    it('throws when maxLength is negative', () => {
      expect(() => chunkText('text', -1)).toThrow('maxLength must be a positive number');
    });

    it('throws when maxLength is -Infinity or NaN-like', () => {
      expect(() => chunkText('text', -100)).toThrow('maxLength must be a positive number');
    });
  });

  // ─── Under-limit / exactly-at-limit single chunk ────────────────────────

  describe('single chunk when within limit', () => {
    it('returns single chunk when text is shorter than maxLength', () => {
      expect(chunkText('Hello', 100)).toEqual(['Hello']);
    });

    it('returns single chunk when text length equals maxLength', () => {
      const text = 'Hello World'; // 11 chars (no spaces trimmed)
      expect(chunkText(text, text.length)).toEqual([text]);
    });

    it('trims text and returns single chunk when trimmed length is within limit', () => {
      // Leading/trailing whitespace is stripped; result is one chunk
      expect(chunkText('  Hello  ', 10)).toEqual(['Hello']);
    });
  });

  // ─── Multi-sentence greedy packing ──────────────────────────────────────

  describe('multi-sentence greedy packing', () => {
    it('packs "Hello. World!" with maxLength 7', () => {
      // Sentences: "Hello." (6 chars), " World!" (7 chars)
      // "Hello." fits (6 ≤ 7). Adding " World!" would make 13 > 7 → push.
      // " World!" fits (7 ≤ 7) → push.
      expect(chunkText('Hello. World!', 7)).toEqual(['Hello.', ' World!']);
    });

    it('keeps multiple short sentences together when space permits', () => {
      // "Hi." (3) + " Bye." (5) = 8 ≤ 10 → one chunk
      expect(chunkText('Hi. Bye.', 10)).toEqual(['Hi. Bye.']);
    });

    it('splits when second sentence would push past limit', () => {
      // "Hello." (6) + " World." (7) = 13 > 10 → two chunks
      expect(chunkText('Hello. World.', 10)).toEqual(['Hello.', ' World.']);
    });

    it('handles three sentences with varied lengths', () => {
      const result = chunkText('A. Longer one. Short.', 12);
      // "A." (2) + " Longer one." (12) = 14 > 12 → push "A.", current=" Longer one."
      // " Longer one." (12) + " Short." (7) = 19 > 12 → push " Longer one.", current=" Short."
      // flush " Short."
      expect(result).toEqual(['A.', ' Longer one.', ' Short.']);
      for (const chunk of result) {
        expect(chunk.length).toBeLessThanOrEqual(12);
      }
    });
  });

  // ─── Over-long single sentence hard-split ───────────────────────────────

  describe('over-long single sentence hard-split', () => {
    it('slices a sentence longer than maxLength into equal pieces', () => {
      const result = chunkText('abcdefghij', 3);
      expect(result).toEqual(['abc', 'def', 'ghi', 'j']);
    });

    it('preserves all characters in hard-split', () => {
      const text = 'abcdefghijklmno';
      const result = chunkText(text, 4);
      expect(result.join('')).toBe(text);
      for (const chunk of result) {
        expect(chunk.length).toBeLessThanOrEqual(4);
      }
    });

    it('handles a single sentence exactly double maxLength', () => {
      expect(chunkText('123456', 3)).toEqual(['123', '456']);
    });

    it('handles a single character sentence over limit (edge case)', () => {
      // A sentence "X" with maxLength 0 would throw; maxLength 1 works fine
      expect(chunkText('X', 1)).toEqual(['X']);
    });
  });

  // ─── Invariants ─────────────────────────────────────────────────────────

  describe('invariants', () => {
    it('no chunk exceeds maxLength across varied inputs', () => {
      const inputs = [
        { text: 'Hello. World! How are you?', max: 8 },
        { text: 'A. B. C. D. E. F.', max: 4 },
        { text: 'Short.', max: 100 },
        { text: 'abcdefghijklmnopqrstuvwxyz', max: 5 },
        { text: 'One. Two. Three. Four. Five.', max: 10 },
        { text: 'Hello World', max: 6 },
      ];

      for (const { text, max } of inputs) {
        for (const chunk of chunkText(text, max)) {
          expect(chunk.length).toBeLessThanOrEqual(max);
        }
      }
    });

    it('content preservation: chunks.join("") reconstructs trimmed input', () => {
      const inputs = [
        'Hello. World!',
        'abcdefghijklmnopqrstuvwxyz',
        'One. Two. Three.',
        'No punctuation here',
      ];

      for (const text of inputs) {
        const result = chunkText(text, 5);
        expect(result.join('')).toBe(text);
      }
    });
  });

  // ─── Mixed: normal sentences + over-long sentence ───────────────────────

  describe('mixed normal and over-long sentences', () => {
    it('handles normal sentences followed by an over-long sentence', () => {
      // "Hi." (3) + " ThisIsAVeryLongSentence" (23) with maxLength 10
      const result = chunkText('Hi. ThisIsAVeryLongSentence', 10);
      // "Hi." fits in first chunk (3 ≤ 10).
      // " ThisIsAVeryLongSentence" is 24 chars > 10 → flush current, hard-split
      expect(result[0]).toBe('Hi.');
      expect(result.slice(1).join('')).toBe(' ThisIsAVeryLongSentence');
      for (const chunk of result) {
        expect(chunk.length).toBeLessThanOrEqual(10);
      }
    });

    it('handles over-long sentence followed by normal sentences', () => {
      // "Overlong" (8) + " Hi." (4) with maxLength 5
      // "Overlong" (8) > 5 → hard-split: ["Overl", "ong"]
      // " Hi." (4) ≤ 5 → current=" Hi.", flush
      const result = chunkText('Overlong Hi.', 5);
      expect(result).toEqual(['Overl', 'ong', ' Hi.']);
      for (const chunk of result) {
        expect(chunk.length).toBeLessThanOrEqual(5);
      }
    });

    it('handles multiple over-long sentences interspersed', () => {
      const result = chunkText('abcdef ghijkl mnopqr', 4);
      // "abcdef" → ["abcd", "ef"]
      // " ghijkl" → [" ghi", "jkl"]
      // " mnopqr" → [" mno", "pqr"]
      for (const chunk of result) {
        expect(chunk.length).toBeLessThanOrEqual(4);
      }
      expect(result.join('')).toBe('abcdef ghijkl mnopqr');
    });

    it('handles over-long sentence at end with preceding normal chunk', () => {
      const result = chunkText('Hi. VeryLongSentenceHere', 10);
      // "Hi." (3) fits. " VeryLongSentenceHere" (21) > 10 → flush "Hi.", hard-split
      expect(result[0]).toBe('Hi.');
      for (const chunk of result) {
        expect(chunk.length).toBeLessThanOrEqual(10);
      }
      expect(result.join('')).toBe('Hi. VeryLongSentenceHere');
    });
  });
});

